import { custoProduto, custoItem, fmt } from './db';

const LOGO_B64 = "";

const EMPRESA = {
  nome: 'M V VIEIRA PEREIRA LTDA',
  cnpj: 'CNPJ: 59.595.908/0001-38',
  endereco: 'Rua Eletricista Guilherme, Nº: 833 – Fátima',
  cep: 'CEP: 64049-486 – Teresina (PI)',
  fone: 'Fone: (86) 99801-6101',
  email: 'E-mail: marcus@fardamais.com',
};

const COR_LARANJA = [220, 100, 20];
const COR_ESCURO  = [40, 40, 40];
const COR_CINZA   = [100, 100, 100];
const COR_LARANJA_CLARO = [255, 245, 235];
const W = 210;

// ─── helpers visuais ──────────────────────────────────────────────────────────

function linhaLaranja(doc, y, espessura = 0.6) {
  doc.setDrawColor(...COR_LARANJA);
  doc.setLineWidth(espessura);
  doc.line(14, y, W - 14, y);
}

function secao(doc, texto, y) {
  doc.setFillColor(...COR_LARANJA);
  doc.rect(14, y - 1, W - 28, 6, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8.5);
  doc.setFont('helvetica', 'bold');
  doc.text(texto, 16, y + 3.5);
}

function rodape(doc, texto) {
  linhaLaranja(doc, 282, 0.5);
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(...COR_CINZA);
  doc.text(texto, W / 2, 287, { align: 'center' });
}

function cabecalhoComLogo(doc, titulo, sub) {
  // Logo com proporção correta (não achata)
  linhaLaranja(doc, 8, 1.2);
  try {
    // Calcula altura proporcional: imagem original é retrato, usa largura 22mm
    doc.addImage(LOGO_B64, 'JPEG', 14, 10, 22, 22);
  } catch (e) {}
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...COR_ESCURO);
  doc.text(titulo, 42, 17);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(...COR_CINZA);
  doc.text(sub, 42, 23);
  linhaLaranja(doc, 34, 0.5);
}

// ─── ORÇAMENTO INTERNO ────────────────────────────────────────────────────────
export async function exportarOrcamentoPDF(orcamento, produtos = []) {
  const { default: jsPDF } = await import('jspdf');
  await import('jspdf-autotable');
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  cabecalhoComLogo(doc, 'ORÇAMENTO INTERNO', 'FardaMais Uniformes  |  Uso restrito — não compartilhar com cliente');

  // Bloco cliente
  let y = 38;
  doc.setFillColor(...COR_LARANJA_CLARO);
  doc.rect(14, y, W - 28, 13, 'F');
  doc.setFontSize(7.5); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
  doc.text('CLIENTE', 17, y + 5);
  doc.setFontSize(10); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_ESCURO);
  doc.text(orcamento.cliente || '—', 17, y + 11);
  doc.setFontSize(8); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_CINZA);
  const dataFmt = orcamento.data ? new Date(orcamento.data + 'T12:00:00').toLocaleDateString('pt-BR') : new Date().toLocaleDateString('pt-BR');
  doc.text('Data: ' + dataFmt, W - 15, y + 5, { align: 'right' });
  doc.text('Nº ' + String(orcamento.id || '').slice(0, 8).toUpperCase(), W - 15, y + 11, { align: 'right' });
  y += 17;

  // Tabela principal — uma linha por produto com preço unitário e total individuais
  const itens = orcamento.itens || [];
  const totalQtd = itens.reduce((a, it) => a + (parseInt(it.qtd) || 0), 0);
  const vendaTotal = parseFloat(orcamento.venda || 0);
  const custoTotalOrc = parseFloat(orcamento.custo_total || 0);

  const rows = itens.map(it => {
    const p = produtos.find(x => x.id === it.prodId);
    const custoUnit = p ? custoProduto(p) : 0;
    const qtd = parseInt(it.qtd) || 0;
    const custoTotalItem = custoUnit * qtd;
    // Preço de venda proporcional ao custo de cada produto
    const proporcao = custoTotalOrc > 0 ? custoUnit / (custoTotalOrc / (totalQtd || 1)) / (totalQtd || 1) : 0;
    const vendaUnit = totalQtd > 0 ? vendaTotal / totalQtd : 0;
    const vendaTotalItem = vendaUnit * qtd;
    const lucroItem = vendaTotalItem - custoTotalItem;
    const margemItem = custoTotalItem > 0 ? (lucroItem / custoTotalItem * 100) : 0;
    return [
      it.nome,
      String(qtd),
      fmt(custoUnit),
      fmt(custoTotalItem),
      fmt(vendaUnit),
      fmt(vendaTotalItem),
      margemItem.toFixed(1) + '%',
    ];
  });

  doc.autoTable({
    startY: y,
    head: [['Produto', 'Qtd', 'Custo Unit.', 'Custo Total', 'Venda Unit.', 'Venda Total', 'Margem']],
    body: rows,
    headStyles: { fillColor: COR_LARANJA, textColor: [255,255,255], fontStyle: 'bold', fontSize: 8 },
    bodyStyles: { fontSize: 8, textColor: COR_ESCURO },
    alternateRowStyles: { fillColor: [255, 250, 245] },
    columnStyles: {
      0: { cellWidth: 52 },
      1: { cellWidth: 12, halign: 'center' },
      2: { cellWidth: 26, halign: 'right' },
      3: { cellWidth: 26, halign: 'right' },
      4: { cellWidth: 26, halign: 'right' },
      5: { cellWidth: 26, halign: 'right' },
      6: { cellWidth: 18, halign: 'right' },
    },
    margin: { left: 14, right: 14 },
    styles: { lineColor: [230, 200, 180], lineWidth: 0.3 },
  });

  y = doc.lastAutoTable.finalY + 6;

  // ── Composição de custos por produto ──
  if (y < 230) {
    secao(doc, 'COMPOSIÇÃO DE CUSTOS POR PRODUTO', y);
    y += 7;
    for (const it of itens) {
      const p = produtos.find(x => x.id === it.prodId);
      if (!p || !p.custos || p.custos.length === 0) continue;
      if (y > 260) { doc.addPage(); y = 20; }

      doc.setFontSize(8.5); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
      doc.text(it.nome + ' (qtd: ' + it.qtd + ')', 14, y);
      y += 4;

      const compRows = p.custos.map(c => {
        const custo = custoItem(c);
        return [
          c.tipo === 'material' ? '🧵 Material' : c.tipo === 'servico' ? '🪡 Serviço' : '✏️ Manual',
          c.nome,
          String(c.quantidade),
          c.tipo === 'material' ? fmt(c.valorRef) + '/' + c.medida + ' ÷ ' + c.rendimento : c.tipo === 'servico' ? fmt(c.valorRef) + '/peça' : fmt(c.valorManual),
          fmt(custo),
        ];
      });
      const subtotal = p.custos.reduce((a, c) => a + custoItem(c), 0);
      const impostoV = p.usarImposto !== false ? subtotal * (parseFloat(p.imposto) || 0.07) : 0;

      doc.autoTable({
        startY: y,
        head: [['Tipo', 'Descrição', 'Qtd', 'Valor Ref.', 'Custo']],
        body: [
          ...compRows,
          [{ content: 'Imposto NF', colSpan: 4, styles: { halign: 'right', fontStyle: 'italic', textColor: [150,100,20] } }, { content: fmt(impostoV), styles: { halign: 'right', fontStyle: 'italic', textColor: [150,100,20] } }],
          [{ content: 'CUSTO UNITÁRIO TOTAL', colSpan: 4, styles: { halign: 'right', fontStyle: 'bold' } }, { content: fmt(subtotal + impostoV), styles: { halign: 'right', fontStyle: 'bold', textColor: COR_LARANJA } }],
        ],
        headStyles: { fillColor: [80, 80, 80], textColor: [255,255,255], fontStyle: 'bold', fontSize: 7.5 },
        bodyStyles: { fontSize: 7.5, textColor: COR_ESCURO },
        alternateRowStyles: { fillColor: [250, 250, 250] },
        columnStyles: {
          0: { cellWidth: 22 },
          1: { cellWidth: 68 },
          2: { cellWidth: 14, halign: 'center' },
          3: { cellWidth: 48 },
          4: { cellWidth: 24, halign: 'right' },
        },
        margin: { left: 14, right: 14 },
        styles: { lineColor: [210, 210, 210], lineWidth: 0.2 },
      });
      y = doc.lastAutoTable.finalY + 5;
    }
  }

  // ── Resumo financeiro ──
  if (y > 250) { doc.addPage(); y = 20; }
  secao(doc, 'RESUMO FINANCEIRO', y);
  y += 7;

  const lucro = vendaTotal - custoTotalOrc;
  const roi = custoTotalOrc > 0 ? (lucro / custoTotalOrc * 100) : 0;
  const margem = vendaTotal > 0 ? (lucro / vendaTotal * 100) : 0;

  doc.setFillColor(...COR_LARANJA_CLARO);
  doc.rect(14, y, W - 28, 28, 'F');
  doc.setFontSize(8.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO);
  const c1 = 18, c2 = 80, c3 = 140;
  doc.text('Custo interno total:', c1, y + 8); doc.setFont('helvetica', 'bold'); doc.text(fmt(custoTotalOrc), c1 + 45, y + 8);
  doc.setFont('helvetica', 'normal'); doc.text('Valor de venda:', c1, y + 16); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA); doc.text(fmt(vendaTotal), c1 + 45, y + 16);
  doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO); doc.text('Lucro líquido:', c2, y + 8); doc.setFont('helvetica', 'bold');
  doc.setTextColor(lucro >= 0 ? 30 : 200, lucro >= 0 ? 140 : 50, 30);
  doc.text(fmt(lucro), c2 + 35, y + 8);
  doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO); doc.text('Margem:', c2, y + 16); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA); doc.text(margem.toFixed(1) + '%', c2 + 35, y + 16);
  doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO); doc.text('ROI:', c3, y + 8); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA); doc.text(roi.toFixed(1) + '%', c3 + 20, y + 8);
  doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO); doc.text('Total peças:', c3, y + 16); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_ESCURO); doc.text(String(totalQtd), c3 + 30, y + 16);
  if (orcamento.obs) { doc.setFont('helvetica', 'italic'); doc.setFontSize(7.5); doc.setTextColor(100,100,100); doc.text('Obs: ' + orcamento.obs, 18, y + 24); }

  rodape(doc, 'FardaMais Uniformes  |  Documento interno — não compartilhar com cliente');
  doc.save('orcamento_interno_' + (orcamento.cliente || 'cliente').replace(/\s/g,'_') + '_' + Date.now() + '.pdf');
}

// ─── ORÇAMENTO EXTERNO ────────────────────────────────────────────────────────
export async function exportarOrcamentoExternoPDF(orcamento, produtos = []) {
  const { default: jsPDF } = await import('jspdf');
  await import('jspdf-autotable');
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const numDoc = String(orcamento.id || '').slice(0, 8).toUpperCase();
  const dataFmt = orcamento.data ? new Date(orcamento.data + 'T12:00:00').toLocaleDateString('pt-BR') : new Date().toLocaleDateString('pt-BR');

  // ── Cabeçalho ──
  linhaLaranja(doc, 8, 1.2);
  try { doc.addImage(LOGO_B64, 'JPEG', 14, 10, 22, 22); } catch(e) {}

  // Dados empresa lado direito
  doc.setFontSize(10); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_ESCURO);
  doc.text(EMPRESA.nome, W - 14, 14, { align: 'right' });
  doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_CINZA);
  doc.text(EMPRESA.cnpj, W - 14, 19, { align: 'right' });
  doc.text(EMPRESA.endereco + '  ' + EMPRESA.cep, W - 14, 23, { align: 'right' });
  doc.text(EMPRESA.fone + '  |  ' + EMPRESA.email, W - 14, 27, { align: 'right' });

  linhaLaranja(doc, 34, 0.5);

  doc.setFontSize(13); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
  doc.text('ORÇAMENTO DE VENDA', 14, 40);
  doc.setFontSize(8); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_CINZA);
  doc.text('Nº: ' + numDoc, W - 14, 37, { align: 'right' });
  doc.text('Data: ' + dataFmt, W - 14, 42, { align: 'right' });

  // ── Dados do cliente ──
  let y = 45;
  doc.setDrawColor(...COR_LARANJA); doc.setLineWidth(0.4);
  doc.rect(14, y, W - 28, 22);
  doc.setFontSize(7.5); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
  doc.text('DADOS DO CLIENTE', 17, y + 5);

  const de = orcamento.dadosEmpresa || {};
  const nomeCliente = de.razaoSocial || orcamento.cliente || '—';
  doc.setFontSize(9); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_ESCURO);
  doc.text(nomeCliente, 17, y + 11);
  doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_CINZA);
  const l2 = [de.cnpj, de.endereco, de.cidade].filter(Boolean).join('  |  ');
  const l3 = [de.telefone ? 'Fone: ' + de.telefone : '', de.responsavel ? 'Contato: ' + de.responsavel : ''].filter(Boolean).join('  |  ');
  if (l2) doc.text(l2, 17, y + 16);
  if (l3) doc.text(l3, 17, y + 21);
  y += 26;

  // ── Condições ──
  doc.setFillColor(...COR_LARANJA_CLARO);
  doc.rect(14, y, W - 28, 8, 'F');
  doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(80,80,80);
  doc.text('Validade: ' + (orcamento.validade || '05 dias'), 17, y + 5.5);
  doc.text('Pagamento: ' + (orcamento.pagamento || 'À Vista'), 70, y + 5.5);
  doc.text('Prazo Entrega: ' + (orcamento.prazo || 'A combinar'), 130, y + 5.5);
  y += 12;

  // ── Tabela de itens — preço por produto ──
  const itens = orcamento.itens || [];
  const totalQtd = itens.reduce((a, it) => a + (parseInt(it.qtd) || 0), 0);
  const vendaTotal = parseFloat(orcamento.venda || 0);
  const custoTotalOrc = parseFloat(orcamento.custo_total || 0);

  // Cada produto recebe preço proporcional ao seu custo
  const rows = itens.map((it, i) => {
    const p = produtos.find(x => x.id === it.prodId);
    const custoUnit = p ? custoProduto(p) : 0;
    const qtd = parseInt(it.qtd) || 0;
    // Preço de venda proporcional: venda_unit_produto = (custo_unit_produto / custo_unit_medio) * venda_unit_media
    const custoMedio = custoTotalOrc / (totalQtd || 1);
    const vendaMedia = vendaTotal / (totalQtd || 1);
    const vendaUnit = custoMedio > 0 ? (custoUnit / custoMedio) * vendaMedia : vendaMedia;
    const totalItem = vendaUnit * qtd;
    return [String(i+1).padStart(3,'0'), it.nome, String(qtd), 'PC', fmt(vendaUnit), fmt(totalItem)];
  });

  const totalVendaReal = rows.reduce((a, r) => {
    const v = parseFloat(r[5].replace('R$ ','').replace('.','').replace(',','.')) || 0;
    return a + v;
  }, 0);

  doc.autoTable({
    startY: y,
    head: [['Cód.', 'Descrição do Produto', 'Quantidade', 'Un.', 'Vlr Unitário', 'Preço Total']],
    body: rows,
    headStyles: { fillColor: COR_LARANJA, textColor: [255,255,255], fontStyle: 'bold', fontSize: 8.5 },
    bodyStyles: { fontSize: 9, textColor: COR_ESCURO },
    alternateRowStyles: { fillColor: [255, 250, 245] },
    columnStyles: {
      0: { cellWidth: 16, halign: 'center' },
      1: { cellWidth: 74 },
      2: { cellWidth: 24, halign: 'center' },
      3: { cellWidth: 12, halign: 'center' },
      4: { cellWidth: 30, halign: 'right' },
      5: { cellWidth: 30, halign: 'right' },
    },
    margin: { left: 14, right: 14 },
    styles: { lineColor: [230, 200, 180], lineWidth: 0.3 },
  });

  const finalY = doc.lastAutoTable.finalY + 4;

  // ── Bloco totais ──
  const totW = 82, totX = W - 14 - totW;
  doc.setDrawColor(...COR_LARANJA); doc.setLineWidth(0.4);
  doc.rect(totX, finalY, totW, 30);
  doc.setFontSize(8); doc.setFont('helvetica', 'normal'); doc.setTextColor(80,80,80);
  doc.text('Quantidade Total de Itens:', totX + 3, finalY + 7);
  doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_ESCURO);
  doc.text(String(totalQtd), totX + totW - 3, finalY + 7, { align: 'right' });
  doc.setFont('helvetica', 'normal'); doc.setTextColor(80,80,80);
  doc.text('Total dos Produtos:', totX + 3, finalY + 14);
  doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_ESCURO);
  doc.text(fmt(vendaTotal), totX + totW - 3, finalY + 14, { align: 'right' });
  linhaLaranja(doc, finalY + 19, 0.3);
  doc.setFontSize(11); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
  doc.text('Total:', totX + 3, finalY + 27);
  doc.setTextColor(...COR_ESCURO);
  doc.text(fmt(vendaTotal), totX + totW - 3, finalY + 27, { align: 'right' });

  // Frete
  doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_CINZA);
  doc.text('Frete: ' + fmt(0) + '  |  Tipo do Frete: FOB', totX, finalY + 35);

  // Observações
  if (orcamento.obs) {
    doc.setFontSize(7.5); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
    doc.text('Observações:', 14, finalY + 5);
    doc.setFont('helvetica', 'normal'); doc.setTextColor(70,70,70);
    const obsLines = doc.splitTextToSize(orcamento.obs, totX - 20);
    doc.text(obsLines, 14, finalY + 11);
  }

  // ── Assinaturas ──
  const assinY = finalY + 42;
  if (assinY < 265) {
    doc.setDrawColor(180,180,180); doc.setLineWidth(0.3);
    const assinW = (W - 28 - 10) / 2;
    doc.line(14, assinY, 14 + assinW, assinY);
    doc.line(14 + assinW + 10, assinY, 14 + assinW * 2 + 10, assinY);
    doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_CINZA);
    doc.text('(Visto do Comprador)', 14 + assinW / 2, assinY + 5, { align: 'center' });
    doc.text('Vendedor', 14 + assinW + 10 + assinW / 2, assinY + 5, { align: 'center' });
  }

  rodape(doc, 'FardaMais Uniformes  |  ' + EMPRESA.fone + '  |  ' + EMPRESA.email);
  doc.save('orcamento_cliente_' + (orcamento.cliente || 'cliente').replace(/\s/g,'_') + '_' + numDoc + '.pdf');
}

// ─── PROTOCOLO DE ENTREGA ─────────────────────────────────────────────────────
export async function exportarProtocoloPDF(orcamento) {
  const { default: jsPDF } = await import('jspdf');
  await import('jspdf-autotable');
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const numProtocolo = String(orcamento.id || '').slice(0, 8).toUpperCase();
  const dataFmt = orcamento.data ? new Date(orcamento.data + 'T12:00:00').toLocaleDateString('pt-BR') : new Date().toLocaleDateString('pt-BR');

  cabecalhoComLogo(doc, 'PROTOCOLO DE ENTREGA', 'FardaMais Uniformes  |  Documento de Controle Interno');

  // Nº e data
  doc.setFontSize(8); doc.setFont('helvetica', 'normal'); doc.setTextColor(80,80,80);
  doc.text('Nº: ' + numProtocolo, 14, 39);
  doc.text('Data: ' + dataFmt, W - 14, 39, { align: 'right' });

  // ── Seção 1: Dados empresa ──
  let y = 43;
  secao(doc, '1. DADOS DA EMPRESA RECEPTORA', y); y += 7;

  const de = orcamento.dadosEmpresa || {};
  const camposEmpresa = [
    ['Razão Social / Nome', de.razaoSocial || orcamento.cliente || ''],
    ['CNPJ / CPF', de.cnpj || ''],
    ['Endereço', de.endereco || ''],
    ['Cidade / UF', de.cidade || ''],
    ['Responsável', de.responsavel || ''],
    ['Cargo', de.cargo || ''],
    ['Telefone', de.telefone || ''],
    ['E-mail', de.email || ''],
  ];

  // Dois campos por linha para compactar
  for (let i = 0; i < camposEmpresa.length; i += 2) {
    const [l1, v1] = camposEmpresa[i];
    const [l2, v2] = camposEmpresa[i + 1] || ['', ''];
    doc.setFontSize(7.5); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
    doc.text(l1 + ':', 14, y);
    doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO);
    if (v1) doc.text(v1, 45, y);
    doc.setDrawColor(220,180,140); doc.setLineWidth(0.2);
    doc.line(14, y + 1.2, 98, y + 1.2);

    if (l2) {
      doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
      doc.text(l2 + ':', 105, y);
      doc.setFont('helvetica', 'normal'); doc.setTextColor(...COR_ESCURO);
      if (v2) doc.text(v2, 128, y);
      doc.line(105, y + 1.2, W - 14, y + 1.2);
    }
    y += 7;
  }

  // ── Seção 2: Itens ──
  y += 2;
  secao(doc, '2. ITENS DE FARDAMENTO ENTREGUES', y); y += 4;

  const itensRows = (orcamento.itens || []).map((it, i) => [
    String(i + 1), it.nome || '', String(it.qtd || ''), '', '', '',
  ]);
  while (itensRows.length < 8) { itensRows.push([String(itensRows.length + 1), '', '', '', '', '']); }

  doc.autoTable({
    startY: y,
    head: [['Nº', 'Descrição do Item', 'Qtd.', 'Tamanho', 'Cor', 'Observação']],
    body: itensRows,
    headStyles: { fillColor: COR_LARANJA, textColor: [255,255,255], fontStyle: 'bold', fontSize: 8 },
    bodyStyles: { fontSize: 8, textColor: COR_ESCURO, minCellHeight: 7 },
    alternateRowStyles: { fillColor: [255, 250, 245] },
    columnStyles: {
      0: { cellWidth: 10, halign: 'center' },
      1: { cellWidth: 68 },
      2: { cellWidth: 14, halign: 'center' },
      3: { cellWidth: 24, halign: 'center' },
      4: { cellWidth: 24, halign: 'center' },
      5: { cellWidth: 46 },
    },
    margin: { left: 14, right: 14 },
    styles: { lineColor: [220, 180, 140], lineWidth: 0.3 },
  });
  y = doc.lastAutoTable.finalY + 6;

  // ── Seção 3: Declaração + assinaturas ──
  secao(doc, '3. DECLARAÇÃO DE RECEBIMENTO', y); y += 6;
  doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(70,70,70);
  const decl = 'Declaro que recebi os itens de fardamento listados acima em perfeitas condições, conferidos e aprovados pelo responsável da empresa identificada neste protocolo.';
  const declLines = doc.splitTextToSize(decl, W - 28);
  doc.text(declLines, 14, y);
  y += declLines.length * 4.5 + 5;

  const assinW = (W - 38) / 2;
  const aX1 = 14, aX2 = 14 + assinW + 10;
  doc.setDrawColor(...COR_LARANJA); doc.setLineWidth(0.4);
  doc.rect(aX1, y, assinW, 24);
  doc.setFontSize(8); doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
  doc.text('Responsável pela Entrega', aX1 + assinW / 2, y + 5, { align: 'center' });
  doc.setFont('helvetica', 'normal'); doc.setTextColor(90,90,90);
  doc.text('Assinatura: _______________________', aX1 + 3, y + 13);
  doc.text('Nome: ____________________________', aX1 + 3, y + 20);

  doc.rect(aX2, y, assinW, 24);
  doc.setFont('helvetica', 'bold'); doc.setTextColor(...COR_LARANJA);
  doc.text('Responsável pelo Recebimento', aX2 + assinW / 2, y + 5, { align: 'center' });
  doc.setFont('helvetica', 'normal'); doc.setTextColor(90,90,90);
  doc.text('Assinatura: _______________________', aX2 + 3, y + 13);
  doc.text('Nome: ____________________________', aX2 + 3, y + 20);
  y += 30;

  // ── Seção 4: Observações ──
  if (y < 265) {
    secao(doc, '4. OBSERVAÇÕES GERAIS', y); y += 5;
    doc.setDrawColor(220,180,140); doc.setLineWidth(0.3);
    doc.rect(14, y, W - 28, 14);
    if (orcamento.obs) {
      doc.setFontSize(7.5); doc.setFont('helvetica', 'normal'); doc.setTextColor(70,70,70);
      doc.text(orcamento.obs, 17, y + 6);
    }
  }

  rodape(doc, 'FardaMais Uniformes  |  Via original: Empresa Fornecedora  |  Via cópia: Empresa Receptora');
  doc.save('protocolo_' + (orcamento.cliente || 'cliente').replace(/\s/g,'_') + '_' + numProtocolo + '.pdf');
}
